using System.Net;using System.Net.Http.Json;using System.Text.Json;using DBH.UnitTest.Shared;namespace DBH.UnitTest.UnitTests;/// <summary>/// Good case: Create access request from doctor to patient/// Expected: 201 Created/// </summary>public class ConsentServiceTests_CreateAccessRequest_WithValidData_ShouldCreate : ApiTestBase{    protected override IReadOnlyCollection<string> RequiredServices => new[]    {        "AuthService",        "ConsentService"    };    [SkippableFact]    public async Task CreateAccessRequest_WithValidData_ShouldCreate()    {        await AuthenticateAsDoctorAsync(ConsentClient);        var request = new         {             patientDid = TestSeedData.PatientUserId.ToString(),             requesterDid = TestSeedData.DoctorUserId.ToString(),             reason = "Need to review patient medical history",             requestedDurationDays = 7         };        var response = await PostAsJsonWithRetryAsync(ConsentClient, ApiEndpoints.AccessRequests.Create, request);        Assert.True(            response.StatusCode == HttpStatusCode.Created ||             response.StatusCode == HttpStatusCode.OK,            $"Expected 201 or 200, got {response.StatusCode}");    }}